import React, { useState, useEffect, useCallback, useRef } from 'react';
import './index.css';
import { api } from './api';

// ─── Utilities ────────────────────────────────────────────────────────────────

function initials(name = '') {
  return name.split(' ').map(p => p[0]).join('').slice(0, 2).toUpperCase();
}

function fmtDate(iso = '') {
  if (!iso) return '—';
  const d = new Date(iso + 'T12:00:00');
  return d.toLocaleDateString('en-US', { weekday: 'short', month: 'short', day: 'numeric' });
}

function fmtDateTime(iso = '') {
  if (!iso) return '—';
  return new Date(iso).toLocaleString('en-US', {
    month: 'short', day: 'numeric', hour: 'numeric', minute: '2-digit'
  });
}

// ─── Toast system ─────────────────────────────────────────────────────────────

function useToast() {
  const [toasts, setToasts] = useState([]);
  const add = useCallback((msg, type = 'success') => {
    const id = Date.now();
    setToasts(t => [...t, { id, msg, type }]);
    setTimeout(() => setToasts(t => t.filter(x => x.id !== id)), 3500);
  }, []);
  return { toasts, toast: add };
}

function ToastContainer({ toasts }) {
  return (
    <div className="toast-container">
      {toasts.map(t => (
        <div key={t.id} className={`toast ${t.type}`}>
          <span>{t.type === 'success' ? '✓' : '✕'}</span>
          {t.msg}
        </div>
      ))}
    </div>
  );
}

// ─── Confirm modal ────────────────────────────────────────────────────────────

function ConfirmModal({ title, message, onConfirm, onCancel, danger }) {
  return (
    <div className="modal-overlay" onClick={onCancel}>
      <div className="modal" onClick={e => e.stopPropagation()}>
        <h2>{title}</h2>
        <p className="modal-sub">{message}</p>
        <div className="modal-footer">
          <button className="btn" onClick={onCancel}>Cancel</button>
          <button className={`btn ${danger ? 'btn-danger' : 'btn-primary'}`} onClick={onConfirm}>
            {danger ? 'Delete' : 'Confirm'}
          </button>
        </div>
      </div>
    </div>
  );
}

// ─── Add Rider Modal ──────────────────────────────────────────────────────────

function AddRiderModal({ onAdd, onClose }) {
  const [form, setForm] = useState({ name: '', phone: '', email: '' });
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const set = k => e => setForm(f => ({ ...f, [k]: e.target.value }));

  async function submit() {
    if (!form.name.trim() || !form.phone.trim()) {
      setError('Name and phone number are required.');
      return;
    }
    setLoading(true);
    setError('');
    try {
      const { rider } = await api.addRider(form);
      onAdd(rider);
    } catch (e) {
      setError(e.message);
    } finally {
      setLoading(false);
    }
  }

  return (
    <div className="modal-overlay" onClick={onClose}>
      <div className="modal" onClick={e => e.stopPropagation()}>
        <h2>Add a rider</h2>
        <p className="modal-sub">They'll receive Thursday ride prompts automatically.</p>

        {error && (
          <div style={{ background: 'var(--red-bg)', border: '1px solid rgba(248,113,113,0.3)',
            borderRadius: 'var(--radius)', padding: '9px 12px', fontSize: 13,
            color: 'var(--red)', marginBottom: 14 }}>
            {error}
          </div>
        )}

        <div className="field">
          <label>Full name *</label>
          <input value={form.name} onChange={set('name')} placeholder="e.g. Sarah Chen" autoFocus />
        </div>
        <div className="field">
          <label>Phone / WhatsApp *</label>
          <input value={form.phone} onChange={set('phone')} placeholder="+1 555 000 0000" />
        </div>
        <div className="field">
          <label>Email (optional)</label>
          <input value={form.email} onChange={set('email')} type="email" placeholder="sarah@example.com" />
        </div>

        <div className="modal-footer">
          <button className="btn" onClick={onClose}>Cancel</button>
          <button className="btn btn-primary" onClick={submit} disabled={loading}>
            {loading ? 'Adding…' : 'Add rider'}
          </button>
        </div>
      </div>
    </div>
  );
}

// ─── Edit Rider Modal ─────────────────────────────────────────────────────────

function EditRiderModal({ rider, onSave, onClose }) {
  const [form, setForm] = useState({ name: rider.name, phone: rider.phone, email: rider.email || '' });
  const [loading, setLoading] = useState(false);

  const set = k => e => setForm(f => ({ ...f, [k]: e.target.value }));

  async function submit() {
    setLoading(true);
    try {
      const { rider: updated } = await api.updateRider(rider.id, form);
      onSave(updated);
    } catch (e) {
      alert(e.message);
    } finally { setLoading(false); }
  }

  return (
    <div className="modal-overlay" onClick={onClose}>
      <div className="modal" onClick={e => e.stopPropagation()}>
        <h2>Edit rider</h2>
        <p className="modal-sub">Update {rider.name}'s information.</p>
        <div className="field"><label>Full name</label><input value={form.name} onChange={set('name')} /></div>
        <div className="field"><label>Phone / WhatsApp</label><input value={form.phone} onChange={set('phone')} /></div>
        <div className="field"><label>Email</label><input value={form.email} onChange={set('email')} /></div>
        <div className="modal-footer">
          <button className="btn" onClick={onClose}>Cancel</button>
          <button className="btn btn-primary" onClick={submit} disabled={loading}>
            {loading ? 'Saving…' : 'Save changes'}
          </button>
        </div>
      </div>
    </div>
  );
}

// ─── Requests tab ─────────────────────────────────────────────────────────────

function RequestsTab({ toast }) {
  const [requests, setRequests] = useState([]);
  const [week, setWeek]         = useState('');
  const [loading, setLoading]   = useState(true);

  async function load() {
    setLoading(true);
    try {
      const { requests, week } = await api.getCurrentRequests();
      setRequests(requests);
      setWeek(week);
    } catch (e) { toast(e.message, 'error'); }
    finally { setLoading(false); }
  }

  useEffect(() => { load(); }, []);

  async function setStatus(id, status) {
    try {
      await api.updateStatus(id, status);
      setRequests(rs => rs.map(r => r.id === id ? { ...r, status } : r));
      const msgs = { approved: 'Ride approved ✓', declined: 'Request declined', pending: 'Reset to pending' };
      toast(msgs[status] || 'Updated');
    } catch (e) { toast(e.message, 'error'); }
  }

  async function remove(id) {
    if (!window.confirm('Remove this ride request?')) return;
    try {
      await api.deleteRequest(id);
      setRequests(rs => rs.filter(r => r.id !== id));
      toast('Request removed');
    } catch (e) { toast(e.message, 'error'); }
  }

  const pending  = requests.filter(r => r.status === 'pending').length;
  const approved = requests.filter(r => r.status === 'approved').length;

  return (
    <div>
      <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 18 }}>
        <div>
          <div style={{ fontSize: 15, fontWeight: 600, color: 'var(--text)', marginBottom: 4 }}>
            This week's requests
          </div>
          {week && (
            <div className="week-label">
              🗓 {fmtDate(week)} &nbsp;·&nbsp; {requests.length} responded
              &nbsp;·&nbsp; {pending} pending &nbsp;·&nbsp; {approved} approved
            </div>
          )}
        </div>
        <button className="btn btn-sm" onClick={load}>↺ Refresh</button>
      </div>

      <div className="card">
        {loading ? (
          <div className="empty"><div className="empty-sub">Loading…</div></div>
        ) : requests.length === 0 ? (
          <div className="empty">
            <div className="empty-icon">🚗</div>
            <div className="empty-title">No responses yet</div>
            <div className="empty-sub">
              Riders will appear here after they reply to the Thursday notification.
            </div>
          </div>
        ) : (
          <table>
            <thead>
              <tr>
                <th>Rider</th>
                <th>Phone</th>
                <th>Responded</th>
                <th>Status</th>
                <th>Actions</th>
              </tr>
            </thead>
            <tbody>
              {requests.map(req => (
                <tr key={req.id}>
                  <td>
                    <div className="name-cell">
                      <div className="avatar">{initials(req.rider_name)}</div>
                      <span style={{ fontWeight: 500 }}>{req.rider_name}</span>
                    </div>
                  </td>
                  <td style={{ color: 'var(--text2)', fontFamily: 'var(--mono)', fontSize: 12.5 }}>
                    {req.rider_phone}
                  </td>
                  <td style={{ color: 'var(--text2)', fontSize: 12.5 }}>
                    {fmtDateTime(req.responded_at)}
                  </td>
                  <td>
                    <span className={`badge badge-${req.status}`}>
                      <span className="dot" />
                      {req.status.charAt(0).toUpperCase() + req.status.slice(1)}
                    </span>
                  </td>
                  <td>
                    <div className="action-row">
                      {req.status !== 'approved' && (
                        <button className="btn btn-sm btn-success" onClick={() => setStatus(req.id, 'approved')}>
                          ✓ Approve
                        </button>
                      )}
                      {req.status !== 'declined' && (
                        <button className="btn btn-sm btn-danger" onClick={() => setStatus(req.id, 'declined')}>
                          ✕ Decline
                        </button>
                      )}
                      {req.status !== 'pending' && (
                        <button className="btn btn-sm" onClick={() => setStatus(req.id, 'pending')}>
                          Reset
                        </button>
                      )}
                      <button className="btn btn-sm btn-danger btn-icon" title="Delete" onClick={() => remove(req.id)}>
                        🗑
                      </button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </div>
    </div>
  );
}

// ─── Riders tab ───────────────────────────────────────────────────────────────

function RidersTab({ toast }) {
  const [riders,    setRiders]    = useState([]);
  const [loading,   setLoading]   = useState(true);
  const [showAdd,   setShowAdd]   = useState(false);
  const [editRider, setEditRider] = useState(null);
  const [confirm,   setConfirm]   = useState(null);

  async function load() {
    setLoading(true);
    try {
      const { riders } = await api.getRiders();
      setRiders(riders);
    } catch (e) { toast(e.message, 'error'); }
    finally { setLoading(false); }
  }

  useEffect(() => { load(); }, []);

  function handleAdd(rider) {
    setRiders(rs => [...rs, rider]);
    setShowAdd(false);
    toast(`${rider.name} added`);
  }

  function handleEdit(updated) {
    setRiders(rs => rs.map(r => r.id === updated.id ? updated : r));
    setEditRider(null);
    toast('Rider updated');
  }

  async function toggleActive(rider) {
    try {
      const updated = await api.updateRider(rider.id, { active: rider.active ? 0 : 1 });
      setRiders(rs => rs.map(r => r.id === rider.id ? updated.rider : r));
      toast(updated.rider.active ? `${rider.name} activated` : `${rider.name} deactivated`);
    } catch (e) { toast(e.message, 'error'); }
  }

  async function deleteRider(id, name) {
    try {
      await api.deleteRider(id);
      setRiders(rs => rs.filter(r => r.id !== id));
      toast(`${name} removed`);
    } catch (e) { toast(e.message, 'error'); }
    setConfirm(null);
  }

  return (
    <div>
      <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 18 }}>
        <div>
          <div style={{ fontSize: 15, fontWeight: 600, color: 'var(--text)', marginBottom: 4 }}>All riders</div>
          <div style={{ fontSize: 12, color: 'var(--text3)' }}>
            {riders.length} total · {riders.filter(r => r.active).length} active
          </div>
        </div>
        <button className="btn btn-primary" onClick={() => setShowAdd(true)}>+ Add rider</button>
      </div>

      <div className="card">
        {loading ? (
          <div className="empty"><div className="empty-sub">Loading…</div></div>
        ) : riders.length === 0 ? (
          <div className="empty">
            <div className="empty-icon">👤</div>
            <div className="empty-title">No riders yet</div>
            <div className="empty-sub">Add your first rider using the button above.</div>
          </div>
        ) : (
          <table>
            <thead>
              <tr>
                <th>Name</th>
                <th>Phone</th>
                <th>Email</th>
                <th>Status</th>
                <th>Added</th>
                <th>Actions</th>
              </tr>
            </thead>
            <tbody>
              {riders.map(rider => (
                <tr key={rider.id}>
                  <td>
                    <div className="name-cell">
                      <div className="avatar">{initials(rider.name)}</div>
                      <span style={{ fontWeight: 500 }}>{rider.name}</span>
                    </div>
                  </td>
                  <td style={{ fontFamily: 'var(--mono)', fontSize: 12.5, color: 'var(--text2)' }}>
                    {rider.phone}
                  </td>
                  <td style={{ color: 'var(--text3)', fontSize: 12.5 }}>{rider.email || '—'}</td>
                  <td>
                    <div className="toggle-wrap" onClick={() => toggleActive(rider)}>
                      <div className={`toggle ${rider.active ? 'on' : ''}`}>
                        <div className="toggle-thumb" />
                      </div>
                      <span className={`badge badge-${rider.active ? 'active' : 'inactive'}`}
                        style={{ background: 'none', border: 'none', padding: 0 }}>
                        {rider.active ? 'Active' : 'Inactive'}
                      </span>
                    </div>
                  </td>
                  <td style={{ color: 'var(--text3)', fontSize: 12.5 }}>
                    {fmtDateTime(rider.created_at)}
                  </td>
                  <td>
                    <div className="action-row">
                      <button className="btn btn-sm" onClick={() => setEditRider(rider)}>Edit</button>
                      <button className="btn btn-sm btn-danger"
                        onClick={() => setConfirm({ id: rider.id, name: rider.name })}>
                        Remove
                      </button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </div>

      {showAdd && <AddRiderModal onAdd={handleAdd} onClose={() => setShowAdd(false)} />}
      {editRider && <EditRiderModal rider={editRider} onSave={handleEdit} onClose={() => setEditRider(null)} />}
      {confirm && (
        <ConfirmModal
          title="Remove rider?"
          message={`${confirm.name} will be permanently removed from the system.`}
          danger
          onConfirm={() => deleteRider(confirm.id, confirm.name)}
          onCancel={() => setConfirm(null)}
        />
      )}
    </div>
  );
}

// ─── History tab ──────────────────────────────────────────────────────────────

function HistoryTab({ toast }) {
  const [requests, setRequests] = useState([]);
  const [log,      setLog]      = useState([]);
  const [loading,  setLoading]  = useState(true);

  useEffect(() => {
    Promise.all([api.getAllRequests(), api.getNotifyLog()])
      .then(([r, l]) => { setRequests(r.requests); setLog(l.log); })
      .catch(e => toast(e.message, 'error'))
      .finally(() => setLoading(false));
  }, []);

  // Group by week
  const byWeek = requests.reduce((acc, r) => {
    (acc[r.week_date] = acc[r.week_date] || []).push(r);
    return acc;
  }, {});

  const weeks = Object.keys(byWeek).sort().reverse();

  return (
    <div style={{ display: 'grid', gridTemplateColumns: '1fr 320px', gap: 20 }}>
      <div>
        <div style={{ fontSize: 15, fontWeight: 600, color: 'var(--text)', marginBottom: 18 }}>
          All ride requests
        </div>
        {loading ? (
          <div className="card"><div className="empty"><div className="empty-sub">Loading…</div></div></div>
        ) : weeks.length === 0 ? (
          <div className="card">
            <div className="empty">
              <div className="empty-icon">📋</div>
              <div className="empty-title">No history yet</div>
              <div className="empty-sub">Past ride requests will appear here.</div>
            </div>
          </div>
        ) : weeks.map(w => (
          <div key={w} className="card" style={{ marginBottom: 16 }}>
            <div className="card-header">
              <div>
                <div className="card-title">{fmtDate(w)}</div>
                <div className="card-sub">
                  {byWeek[w].length} request{byWeek[w].length !== 1 ? 's' : ''} ·{' '}
                  {byWeek[w].filter(r => r.status === 'approved').length} approved
                </div>
              </div>
            </div>
            <table>
              <thead>
                <tr><th>Rider</th><th>Status</th><th>Responded</th></tr>
              </thead>
              <tbody>
                {byWeek[w].map(req => (
                  <tr key={req.id}>
                    <td>
                      <div className="name-cell">
                        <div className="avatar">{initials(req.rider_name)}</div>
                        {req.rider_name}
                      </div>
                    </td>
                    <td>
                      <span className={`badge badge-${req.status}`}>
                        <span className="dot" />
                        {req.status.charAt(0).toUpperCase() + req.status.slice(1)}
                      </span>
                    </td>
                    <td style={{ color: 'var(--text2)', fontSize: 12.5 }}>
                      {fmtDateTime(req.responded_at)}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        ))}
      </div>

      {/* Notification log */}
      <div>
        <div style={{ fontSize: 15, fontWeight: 600, color: 'var(--text)', marginBottom: 18 }}>
          Notification history
        </div>
        <div className="card">
          {log.length === 0 ? (
            <div className="empty" style={{ padding: '28px 16px' }}>
              <div className="empty-sub">No notifications sent yet.</div>
            </div>
          ) : log.map(l => (
            <div key={l.id} className="log-row">
              <div>
                <div style={{ fontSize: 13, fontWeight: 500 }}>{fmtDate(l.week_date)}</div>
                <div style={{ fontSize: 11.5, color: 'var(--text3)', marginTop: 2 }}>
                  {fmtDateTime(l.sent_at)}
                </div>
              </div>
              <span className="badge badge-demo">{l.rider_count} sent</span>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

// ─── Settings tab ─────────────────────────────────────────────────────────────

function SettingsTab() {
  const rows = [
    ['Notification day',  'Thursday'],
    ['Notification time', '5:00 PM'],
    ['Ride time',         '6:00 PM'],
    ['Destination',       'Downtown Office'],
    ['Channel',           'SMS / WhatsApp (Twilio)'],
    ['Cron expression',   '0 17 * * 4'],
  ];

  return (
    <div style={{ maxWidth: 580 }}>
      <div style={{ fontSize: 15, fontWeight: 600, color: 'var(--text)', marginBottom: 18 }}>
        Schedule & configuration
      </div>

      <div className="card" style={{ marginBottom: 20 }}>
        <div className="card-header">
          <div>
            <div className="card-title">Ride schedule</div>
            <div className="card-sub">These values are set in your .env file</div>
          </div>
        </div>
        {rows.map(([label, value]) => (
          <div key={label} style={{ display: 'flex', justifyContent: 'space-between',
            alignItems: 'center', padding: '12px 20px',
            borderBottom: '1px solid var(--border)', fontSize: 13 }}>
            <span style={{ color: 'var(--text2)' }}>{label}</span>
            <code style={{ fontFamily: 'var(--mono)', fontSize: 12.5,
              background: 'var(--bg3)', padding: '2px 8px',
              borderRadius: 6, color: 'var(--accent)' }}>{value}</code>
          </div>
        ))}
      </div>

      <div className="card">
        <div className="card-header">
          <div className="card-title">How to configure</div>
        </div>
        <div style={{ padding: '16px 20px', fontSize: 13, color: 'var(--text2)', lineHeight: 1.8 }}>
          <p style={{ marginBottom: 10 }}>
            Copy <code style={{ fontFamily:'var(--mono)', background:'var(--bg3)',
              padding:'1px 6px', borderRadius:4, color:'var(--accent)' }}>.env.example</code> to{' '}
            <code style={{ fontFamily:'var(--mono)', background:'var(--bg3)',
              padding:'1px 6px', borderRadius:4, color:'var(--accent)' }}>.env</code> and fill in:
          </p>
          {[
            ['TWILIO_ACCOUNT_SID', 'Your Twilio Account SID'],
            ['TWILIO_AUTH_TOKEN',  'Your Twilio Auth Token'],
            ['TWILIO_FROM_NUMBER', 'Your Twilio phone number'],
            ['RIDE_TIME',          'e.g. 6:00 PM'],
            ['RIDE_DESTINATION',   'e.g. Downtown Office'],
            ['TZ',                 'IANA timezone, e.g. America/New_York'],
          ].map(([k, v]) => (
            <div key={k} style={{ display:'flex', gap:8, marginBottom:6, alignItems:'flex-start' }}>
              <code style={{ fontFamily:'var(--mono)', background:'var(--bg3)',
                padding:'1px 6px', borderRadius:4, color:'var(--accent)',
                fontSize:12, whiteSpace:'nowrap' }}>{k}</code>
              <span style={{ color:'var(--text3)', fontSize:12.5 }}>{v}</span>
            </div>
          ))}
          <p style={{ marginTop:14, color:'var(--text3)' }}>
            For the Twilio webhook, point your Twilio number's incoming message URL to:<br/>
            <code style={{ fontFamily:'var(--mono)', background:'var(--bg3)',
              padding:'2px 8px', borderRadius:4, color:'var(--green)',
              fontSize:12 }}>https://your-domain.com/api/webhook/twilio</code>
          </p>
        </div>
      </div>
    </div>
  );
}

// ─── Notify modal ─────────────────────────────────────────────────────────────

function NotifyModal({ onClose, onDone, toast }) {
  const [loading, setLoading] = useState(false);
  const [result,  setResult]  = useState(null);

  async function send() {
    setLoading(true);
    try {
      const data = await api.sendNotification();
      setResult(data);
      toast(`Notification sent to ${data.sent} rider(s)`);
    } catch (e) {
      toast(e.message, 'error');
      onClose();
    } finally { setLoading(false); }
  }

  if (result) {
    return (
      <div className="modal-overlay" onClick={onClose}>
        <div className="modal" onClick={e => e.stopPropagation()}>
          <h2>Notification sent ✓</h2>
          <p className="modal-sub">Results for {fmtDate(result.thursdayDate)}</p>
          <div style={{ maxHeight: 220, overflow: 'auto' }}>
            {(result.results || []).map((r, i) => (
              <div key={i} style={{ display:'flex', justifyContent:'space-between',
                padding:'8px 0', borderBottom:'1px solid var(--border)',
                fontSize:13 }}>
                <span>{r.rider}</span>
                <span className={`badge badge-${r.status === 'sent' ? 'approved' : r.status === 'demo' ? 'demo' : 'declined'}`}>
                  {r.status}
                </span>
              </div>
            ))}
          </div>
          <div className="modal-footer">
            <button className="btn btn-primary" onClick={onClose}>Done</button>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="modal-overlay" onClick={onClose}>
      <div className="modal" onClick={e => e.stopPropagation()}>
        <h2>Send ride notification</h2>
        <p className="modal-sub">
          This will send a "do you want a ride?" message to all active riders right now.
          Normally this happens automatically every Thursday at 5:00 PM.
        </p>
        <div className="modal-footer">
          <button className="btn" onClick={onClose}>Cancel</button>
          <button className="btn btn-primary" onClick={send} disabled={loading}>
            {loading ? 'Sending…' : '🔔 Send to all riders'}
          </button>
        </div>
      </div>
    </div>
  );
}

// ─── Main App ─────────────────────────────────────────────────────────────────

const TABS = [
  { id: 'requests', label: 'Ride requests', icon: '🚗' },
  { id: 'riders',   label: 'Riders',        icon: '👥' },
  { id: 'history',  label: 'History',       icon: '📋' },
  { id: 'settings', label: 'Settings',      icon: '⚙️' },
];

export default function App() {
  const [tab,         setTab]         = useState('requests');
  const [stats,       setStats]       = useState(null);
  const [showNotify,  setShowNotify]  = useState(false);
  const { toasts, toast }             = useToast();

  async function loadStats() {
    try {
      const { stats } = await api.getStats();
      setStats(stats);
    } catch (_) {}
  }

  useEffect(() => { loadStats(); }, [tab]);

  const pendingCount = stats?.thisWeek?.pending || 0;

  return (
    <div className="layout">
      {/* Sidebar */}
      <aside className="sidebar">
        <div className="sidebar-logo">
          <div className="logo-mark">
            <div className="logo-icon">🚗</div>
            <div>
              <div className="logo-text">Ride Coord.</div>
              <div className="logo-sub">admin panel</div>
            </div>
          </div>
        </div>

        <nav className="sidebar-nav">
          {TABS.map(t => (
            <button
              key={t.id}
              className={`nav-item ${tab === t.id ? 'active' : ''}`}
              onClick={() => setTab(t.id)}
            >
              <span className="nav-icon">{t.icon}</span>
              <span>{t.label}</span>
              {t.id === 'requests' && pendingCount > 0 && (
                <span className="nav-badge amber">{pendingCount}</span>
              )}
            </button>
          ))}
        </nav>

        <div className="sidebar-footer">
          <div className="schedule-chip">
            <div className="schedule-chip-label">Next ride</div>
            <div className="schedule-chip-value">
              Thursday
              <span>Notification at 5 PM</span>
            </div>
          </div>
        </div>
      </aside>

      {/* Main */}
      <div className="main">
        {/* Top bar */}
        <div className="topbar">
          <div>
            <div className="page-title">
              {TABS.find(t => t.id === tab)?.label}
            </div>
            {stats && (
              <div className="page-sub">
                {stats.activeRiders} active rider{stats.activeRiders !== 1 ? 's' : ''} ·{' '}
                week of {fmtDate(stats.thisWeek?.date)}
              </div>
            )}
          </div>
          <div className="topbar-actions">
            <button className="btn notify-btn" onClick={() => setShowNotify(true)}>
              🔔 Send notification
            </button>
          </div>
        </div>

        {/* Content */}
        <div className="content">
          {/* Stats row */}
          {stats && (
            <div className="stats-grid">
              <div className="stat-card">
                <div className="stat-label">Total riders</div>
                <div className="stat-value">{stats.totalRiders}</div>
                <div className="stat-sub">{stats.activeRiders} active</div>
              </div>
              <div className="stat-card">
                <div className="stat-label">Responded</div>
                <div className="stat-value">{stats.thisWeek.total}</div>
                <div className="stat-sub">this week</div>
              </div>
              <div className="stat-card">
                <div className="stat-label">Approved</div>
                <div className="stat-value" style={{ color: 'var(--green)' }}>
                  {stats.thisWeek.approved}
                </div>
                <div className="stat-sub">{stats.thisWeek.pending} pending</div>
              </div>
              <div className="stat-card">
                <div className="stat-label">Last notified</div>
                <div className="stat-value" style={{ fontSize: 18 }}>
                  {stats.lastNotification ? fmtDate(stats.lastNotification.week_date) : '—'}
                </div>
                <div className="stat-sub">
                  {stats.lastNotification
                    ? `${stats.lastNotification.rider_count} riders`
                    : 'Never sent'}
                </div>
              </div>
            </div>
          )}

          {/* Tab content */}
          {tab === 'requests' && <RequestsTab toast={toast} />}
          {tab === 'riders'   && <RidersTab   toast={toast} />}
          {tab === 'history'  && <HistoryTab  toast={toast} />}
          {tab === 'settings' && <SettingsTab />}
        </div>
      </div>

      {/* Notify modal */}
      {showNotify && (
        <NotifyModal
          onClose={() => setShowNotify(false)}
          onDone={() => { setShowNotify(false); loadStats(); }}
          toast={toast}
        />
      )}

      <ToastContainer toasts={toasts} />
    </div>
  );
}
